      reflectionHelperMockedStatic.when(() -> ReflectionHelper.isRecord(MyClass.class)).thenReturn(false);

      ObjectConstructor<MyClass> objectConstructor = () -> new MyClass();
      when(constructorConstructor.get(typeToken)).thenReturn(objectConstructor);

      // Instead of mocking private getBoundFields, create a subclass to override it
      ReflectiveTypeAdapterFactory factoryWithOverriddenGetBoundFields = new ReflectiveTypeAdapterFactory(
          constructorConstructor, fieldNamingStrategy, excluder, jsonAdapterFactory, filters) {
        @Override
        @SuppressWarnings("unchecked")
        protected Map<String, ?> getBoundFields(Gson context, TypeToken<?> type, Class<?> raw,
                                                boolean blockInaccessible, boolean isRecord) {
          return Collections.emptyMap();
        }
      };

      ReflectiveTypeAdapterFactory spyFactory = Mockito.spy(factoryWithOverriddenGetBoundFields);

      TypeAdapter<MyClass> adapter = spyFactory.create(gson, typeToken);

      assertNotNull(adapter);
      assertEquals("com.google.gson.internal.bind.FieldReflectionAdapter", adapter.getClass().getName());
    }
  }
